class Solution:
    def maxGcd(self, a, b):
        while b:
            a, b = b, a % b
        return a

    def maxGCDScore(self, nums: List[int], k: int) -> int:
        n = len(nums)
        best = 0

        for l in range(n):
            for r in range(l, n):
                sub = nums[l:r+1]
                g = sub[0]
                for num in sub[1:]:
                    g = self.maxGcd(g, num)
                best = max(best, (r - l + 1) * g)

        for mask in range(1 << n):
            if bin(mask).count('1') > k:
                continue
            arr = nums[:]
            for i in range(n):
                if mask & (1 << i):
                    arr[i] *= 2
            for l in range(n):
                for r in range(l, n):
                    sub = arr[l:r+1]
                    g = sub[0]
                    for num in sub[1:]:
                        g = self.maxGcd(g, num)
                    best = max(best, (r - l + 1) * g)
        return best
